"use strict";
/* Шрифт для PDF (DejaVu Sans, subset: латиниця+кирилиця+валюти вкл. ₴). MIT/Bitstream Vera. */
(function () {
  var mk = window.pdfMake;
  if (!mk) return;
  mk.vfs = mk.vfs || {};
  mk.vfs["MenuSans-Regular.ttf"] = "";
  mk.vfs["MenuSans-Bold.ttf"] = "";
  mk.fonts = Object.assign({
    Roboto: { normal: "Roboto-Regular.ttf", bold: "Roboto-Medium.ttf", italics: "Roboto-Italic.ttf", bolditalics: "Roboto-MediumItalic.ttf" }
  }, mk.fonts, {
    Menu: { normal: "MenuSans-Regular.ttf", bold: "MenuSans-Bold.ttf", italics: "MenuSans-Regular.ttf", bolditalics: "MenuSans-Bold.ttf" }
  });
})();
